solution_code:
#include <iostream>
#include <vector>

int main()
{
    int n;
    std::cin >> n;

    std::vector<int> values;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        values.push_back(x);
    }

    std::cout << "First: " << values[0]       << '\n';
    std::cout << "Last: "  << values[n - 1]   << '\n';

    return 0;
}

