#include <iostream>
#include <vector>

int main()
{
    int n;
    std::cin >> n;

    std::vector<int> data;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        data.push_back(x);
    }

    int mid_index = n / 2;
    std::cout << "Middle: " << data[mid_index] << '\n';

    return 0;
}
